const item = $input.item.json;
const raw = item.content ?? item.message?.content ?? item.response ?? item.text ?? '';

let cleaned = String(raw)
  .replace(/^```json\s*/i, '')
  .replace(/^```\s*/i, '')
  .replace(/\s*```$/i, '')
  .replace(/^json\s*/i, '')
  .trim();

// If the model returned extra text, keep the first JSON object only.
const match = cleaned.match(/\{[\s\S]*\}/);
if (match) cleaned = match[0];

let parsed;
try {
  parsed = JSON.parse(cleaned);
} catch (error) {
  return [{ json: {
    amount: null,
    currency: null,
    category: null,
    description: null,
    date: null,
    parse_error: true,
    raw_response: raw
  }}];
}

function normalizeCurrency(value) {
  if (!value) return null;
  const c = String(value).trim().toUpperCase();
  if (['TAKA', 'TK', '৳'].includes(c)) return 'BDT';
  if (['$', 'DOLLAR', 'DOLLARS'].includes(c)) return 'USD';
  if (['€', 'EURO', 'EUROS'].includes(c)) return 'EUR';
  if (['£', 'POUND', 'POUNDS'].includes(c)) return 'GBP';
  return c;
}

const amount = parsed.amount === null || parsed.amount === undefined ? null : Number(parsed.amount);

return [{ json: {
  amount: Number.isFinite(amount) ? amount : null,
  currency: normalizeCurrency(parsed.currency),
  category: parsed.category || null,
  description: parsed.description || null,
  date: parsed.date || null
}}];

const rows = $input.all();

if (rows.length === 0) {
  return [{ json: { text: "📭 No expenses found!" } }];
}

const start = Math.max(0, rows.length - 10);
const last10 = rows.slice(start);

let message = "📊 *Last 10 Expenses:*\n\n";

last10.forEach((row, index) => {
  const r = row.json;
  const sheetRowNumber = start + index + 1; // data row number in the sheet, excluding header
  message += `#${sheetRowNumber}. ${r.date} — *${r.category}*\n`;
  message += `   ${r.description} — ${r.amount} ${r.currency}\n\n`;
});

const total = last10.reduce((sum, row) => sum + Number(row.json.amount || 0), 0);
const currency = last10[0]?.json.currency || 'BDT';
message += `💰 *Total: ${total.toFixed(0)} ${currency}*\n\n`;
message += `To delete, send: delete <number> e.g. delete ${start + 1}`;

return [{ json: { text: message } }];

