const expenseRows = $('Get expenses').all();
const budgetRows = $('Get Budget').all();

const now = new Date();
const currentMonth = now.getFullYear() + '-' + 
  String(now.getMonth() + 1).padStart(2, '0');

const budget = budgetRows
  .filter(r => r.json.date && r.json.date.startsWith(currentMonth))
  .pop();

if (!budget) {
  return [{ json: { 
    text: "❌ No budget set for this month!\n\nUse: setbudget 5000 BDT" 
  }}];
}

const budgetAmount = parseFloat(budget.json.amount);
const currency = budget.json.currency;

const monthExpenses = expenseRows.filter(r => 
  r.json.date && r.json.date.startsWith(currentMonth)
);

const spent = monthExpenses.reduce((sum, r) => 
  sum + parseFloat(r.json.amount || 0), 0
);

const remaining = budgetAmount - spent;
const percentage = Math.min(100, Math.max(0, 
  Math.round((spent / budgetAmount) * 100)
));
const filled = Math.min(20, Math.max(0, Math.round(percentage / 5)));
const bar = '█'.repeat(filled) + '░'.repeat(20 - filled);

const categoryTotals = {};
monthExpenses.forEach(r => {
  const cat = r.json.category || 'Other';
  categoryTotals[cat] = (categoryTotals[cat] || 0) + 
    parseFloat(r.json.amount || 0);
});

let catBreakdown = '';
Object.entries(categoryTotals)
  .sort((a, b) => b[1] - a[1])
  .forEach(([cat, amt]) => {
    catBreakdown += `  • ${cat}: ${amt.toFixed(0)} ${currency}\n`;
  });

const actualPercentage = Math.round((spent / budgetAmount) * 100);
const status = actualPercentage >= 100 ? '🔴 Over budget!' : 
               actualPercentage >= 80 ? '🟡 Almost at limit!' : 
               '🟢 On track';

const text = `📊 *Monthly Budget Report*
📅 ${currentMonth}

💰 Budget:    ${budgetAmount.toLocaleString()} ${currency}
💸 Spent:     ${spent.toFixed(0)} ${currency}
✅ Remaining: ${remaining.toFixed(0)} ${currency}
📈 Used:      ${actualPercentage}%

\`${bar}\` ${actualPercentage}%

${status}

📂 *By Category:*
${catBreakdown}`;

return [{ json: { text } }];

